INSERT INTO formulas (id, name, vibe, description, created_at, name_meaning, image_url, projection, texture, temperature, feeling, opening_style, avoid, family_weights, best_for, concentration_type, complexity) VALUES (14, 'Linen Whisper', '☁️ clean tea air 👕 fabric skin scent ✨ masculine minimal 🌫 soft projection “สะอาดแบบคนดูแลตัวเอง” ไม่ใช่: perfume ผู้ชายตีหน้า', '☁️ clean tea air 👕 fabric skin scent ✨ masculine minimal 🌫 soft projection “สะอาดแบบคนดูแลตัวเอง” ไม่ใช่: perfume ผู้ชายตีหน้า', '2026-05-23T22:22:14.410506+00:00', NULL, 'https://ppiclbcbiuwbtzavnskl.supabase.co/storage/v1/object/public/formula-images/14-1779948005304.png', NULL, NULL, NULL, NULL, NULL, NULL, '{"Musk":9.3,"Fresh":10,"Spicy":0.7,"Woody":3.9,"Ambery":1.4,"Citrus":4.2,"Floral":1.4,"Gourmand":0}'::jsonb, ARRAY[]::text[], NULL, 'standard') ON CONFLICT (id) DO NOTHING;
INSERT INTO formulas (id, name, vibe, description, created_at, name_meaning, image_url, projection, texture, temperature, feeling, opening_style, avoid, family_weights, best_for, concentration_type, complexity) VALUES (18, 'Linen Ember', 'personality vibe  คนพลังเยอะ มีเสน่ห์ ชัดเจน ร้อนแรง กล้าตัดสินใจ เวลาเข้าห้องมา คนจะรู้สึกถึง presence ทันที  feeling น่าค้นหา sexy แบบมั่นใจ energetic warm magnetic perfume vibe spicy amber woody warm vanilla smoky saffron / cinnamon / tobacco keyword  “กลิ่นของคนที่ใครก็ละสายตาไม่ได้”  opening style  เปิดมาชัด มี impact ติด skin แล้ว sexy ขึ้นเรื่อย ๆ', 'personality vibe
INSERT INTO formulas (id, name, vibe, description, created_at, name_meaning, image_url, projection, texture, temperature, feeling, opening_style, avoid, family_weights, best_for, concentration_type, complexity) VALUES (19, 'Petal Hush', '☁️ soft clean floral  🌷 translucent petal glow  👕 fabric skin scent  ✨ byredo-ish soft atmosphere # **😳 Character**  ไม่ใช่:  🌸 floral perfume counter  แต่เป็น:  🌷 “ดอกไม้จาง ๆ บนเสื้อสะอาด”  # **💡 Mood**  ☁️ airy softness  👕 clean fabric  🛏 skin warmth  🌷 floral glow บาง ๆ  ✨ quiet luxury', '☁️ soft clean floral  🌷 translucent petal glow  👕 fabric skin scent  ✨ byredo-ish soft atmosphere # **😳 Character**  ไม่ใช่:  🌸 floral perfume counter  แต่เป็น:  🌷 “ดอกไม้จาง ๆ บนเสื้อสะอาด”  # **💡 Mood**  ☁️ airy softness  👕 clean fabric  🛏 skin warmth  🌷 floral glow บาง ๆ  ✨ quiet luxury', '2026-05-28T08:55:27.486603+00:00', 'เสียงกระซิบของดอกไม้”', 'https://ppiclbcbiuwbtzavnskl.supabase.co/storage/v1/object/public/formula-images/19-1779962252536.png', 'aura', 'airy,creamy,powdery', 'neutral,warm', 'effortless_luxury,approachable,soft_smooth,whisper_scent', 'soft,quiet', '{"presets":["sharp_citrus","metallic_fresh","spicy_woods","masculine_cologne","harsh_aquatic","powder_bomb"],"custom":""}', '{"Musk":8,"Fresh":8.1,"Spicy":0,"Woody":2,"Ambery":1.3,"Citrus":2.1,"Floral":7.5,"Gourmand":0}'::jsonb, ARRAY[]::text[], NULL, 'standard') ON CONFLICT (id) DO NOTHING;
INSERT INTO formulas (id, name, vibe, description, created_at, name_meaning, image_url, projection, texture, temperature, feeling, opening_style, avoid, family_weights, best_for, concentration_type, complexity) VALUES (20, 'Aura Florale', 'Fresh airy floral with a soft Korean luxury aesthetic.  A brighter and more diffusive scent than Petal Hush, with a gentle floral freshness that feels clean, feminine, and modern without becoming sharp or overpowering.  Inspired by the softness of YSL women fragrances, but lighter, airier, and more transparent. Floral notes should feel smooth and blended into the air rather than dense or overly sweet.  The scent should project softly around the body with a luminous clean aura, while still feeling approachable and comfortable.  Cool and refreshing in a soft way — not icy, metallic, or heavily aquatic.  Avoid: sharp lemon/lime citrus, harsh aquatic freshness, strong woody spice, heavy powder, aggressive sweetness, and masculine cologne vibes.', 'Fresh airy floral with a soft Korean luxury aesthetic.
INSERT INTO formulas (id, name, vibe, description, created_at, name_meaning, image_url, projection, texture, temperature, feeling, opening_style, avoid, family_weights, best_for, concentration_type, complexity) VALUES (21, 'Air Bloom', '☁️ fresh floral ❄️ cool clean ✨ brighter projection 🌸 modern feminine 🫧 soft YSL women vibe', '☁️ fresh floral
INSERT INTO formulas (id, name, vibe, description, created_at, name_meaning, image_url, projection, texture, temperature, feeling, opening_style, avoid, family_weights, best_for, concentration_type, complexity) VALUES (23, 'Thé Caresse', 'Soft cool tea skin scent with a quiet luxury aesthetic. A smooth and airy green tea fragrance that feels calming, clean, and modern without becoming bitter, dry, or sharp. The scent should open with a cool leafy freshness and soft tea air rather than citrus sparkle. Fresh, but diffused and gentle — like cool air passing through soft fabric and clean skin. Inspired by the comforting softness of skin scents rather than loud fresh perfumes. Elegant and minimal, with subtle projection that softly trails when walking by, while staying comfortable indoors. Long-lasting on skin with a smooth musky base, creating the feeling of naturally clean skin touched by cool green tea air. Avoid: sharp lemon/lime citrus, bitter tea dryness, metallic freshness, strong aquatic notes, harsh woods, powder-heavy sweetness, and aggressive projection.', 'Soft cool tea skin scent with a quiet luxury aesthetic. A smooth and airy green tea fragrance that feels calming, clean, and modern without becoming bitter, dry, or sharp. The scent should open with a cool leafy freshness and soft tea air rather than citrus sparkle. Fresh, but diffused and gentle — like cool air passing through soft fabric and clean skin. Inspired by the comforting softness of skin scents rather than loud fresh perfumes. Elegant and minimal, with subtle projection that softly trails when walking by, while staying comfortable indoors. Long-lasting on skin with a smooth musky base, creating the feeling of naturally clean skin touched by cool green tea air. Avoid: sharp lemon/lime citrus, bitter tea dryness, metallic freshness, strong aquatic notes, harsh woods, powder-heavy sweetness, and aggressive projection.', '2026-05-29T20:35:59.460544+00:00', 'การลูบเบาของชาเขียว ที่สื่อถึงความนุ่มนวลและการสัมผัสที่อ่อนโยน', 'https://ppiclbcbiuwbtzavnskl.supabase.co/storage/v1/object/public/formula-images/23-1780087757862.png', 'aura', 'airy,creamy,dry', 'cool', 'calm,effortless_luxury,approachable,whisper_scent', 'quiet,slow_bloom', '{"presets":["sharp_citrus","metallic_fresh","bitter_tea","spicy_woods","masculine_cologne","powder_bomb","heavy_sweetness","harsh_aquatic"],"custom":""}', '{"Musk":9.3,"Fresh":8.6,"Spicy":0.7,"Woody":2,"Ambery":2.8,"Citrus":1.9,"Floral":2.1,"Gourmand":2}'::jsonb, ARRAY['Office Day','Casual Date','Daily Wear','Spring & Summer'], NULL, 'standard') ON CONFLICT (id) DO NOTHING;
INSERT INTO formulas (id, name, vibe, description, created_at, name_meaning, image_url, projection, texture, temperature, feeling, opening_style, avoid, family_weights, best_for, concentration_type, complexity) VALUES (27, 'Lumière Douce', 'Clean Skin, Airy Bloom, Freshly Washed Hair, Luxury Skincare, Quiet Luxury, Effortless Elegance, Soft Aura, Modern Minimalism, Sun-Warmed Skin, Well-Groomed Person, Healthy Skin, Natural Elegance, Skin Scent, Soft Musks, Transparent Woods, Your Skin But Better, Second Skin, Soft Floral, Floral Skin, Standing Close', 'A person who genuinely enjoys fragrance and takes pride in smelling good.
INSERT INTO formulas (id, name, vibe, description, created_at, name_meaning, image_url, projection, texture, temperature, feeling, opening_style, avoid, family_weights, best_for, concentration_type, complexity) VALUES (28, 'Thé Caresse', 'Clean Skin, Freshly Washed Hair, Skin Scent, Your Skin But Better, Healthy Skin, Well-Groomed Person, Clean White Shirt, Expensive Fabric, Soft Glow, Quiet Luxury, Effortless Elegance, Natural Elegance, Modern Minimalism, Standing Close, Spring Petals, Soft Tea, Delicate Tea Leaves, Tea & Linen, White Tea, Tea Steam, Soft white tea and delicate tea leaves. Clean skin, freshly washed hair, and crisp white linen. Quiet luxury with a gentle floral touch. Never sharp, bitter, or overly green. The feeling of warmth, comfort, and effortless elegance.', 'คนที่ไม่จำเป็นต้องพูดมากเพื่อให้คนจดจำ
