INSERT INTO formula_versions (id, formula_id, ver, status, rating, notes, blend_date, created_at, batch_ml, projection_actual, longevity_actual, personal_note, is_final, final_date, aging_days, revision_note) VALUES (9, 18, 1, 'Pending', NULL, 'AI แนะนำสูตรเริ่มต้น batch 15ml — สูตร Linen Ember ถูกออกแบบให้เปิดด้วย Bergamot ที่นุ่มนวลไม่แหลมคม แล้วค่อย ๆ เปิดเผยหัวใจของ Hedione ที่สร้าง presence อย่างธรรมชาติ ปิดท้ายด้วย Ambroxan ที่ให้ความอบอุ่นและ magnetic ที่ติดผิวแบบ second-skin effect ตามที่ต้องการ', '2026-05-27', '2026-05-27T22:11:03.121092+00:00', 15, NULL, NULL, NULL, FALSE, NULL, 14, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO formula_versions (id, formula_id, ver, status, rating, notes, blend_date, created_at, batch_ml, projection_actual, longevity_actual, personal_note, is_final, final_date, aging_days, revision_note) VALUES (10, 19, 1, 'Pending', NULL, 'AI แนะนำสูตรเริ่มต้น batch 15ml — สูตรนี้สร้างกลิ่นดอกไม้อ่อนนุ่มที่ใสเหมือนกลีบกุหลาบที่บางและสะอาดบนผิวหนัง hedione เปิดด้วยความหอมโปร่งใสไม่แรงจนเกินไป white tea ให้ความสะอาดอบอุ่นในใจกลางและ galaxolide ปิดท้ายด้วยความนุ่มนวลใกล้ตัวที่ไม่รบกวนแต่น่าค้นพบ', '2026-05-28', '2026-05-28T08:55:27.947851+00:00', 15, NULL, NULL, NULL, FALSE, NULL, 14, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO formula_versions (id, formula_id, ver, status, rating, notes, blend_date, created_at, batch_ml, projection_actual, longevity_actual, personal_note, is_final, final_date, aging_days, revision_note) VALUES (11, 20, 1, 'Pending', NULL, 'AI แนะนำสูตรเริ่มต้น batch 15ml — Aura Florale ใช้ Neroli Oranger เป็นหัวใจหลักเพื่อความสดชื่นแบบดอกไม้ที่นุ่มนวล ผสมกับ Hedione ที่ให้ความโปร่งใสและ airy texture และปิดท้ายด้วย White Musk ที่สร้าง clean aura รอบตัวอย่างหรูหราแต่เข้าถึงง่าย สูตรนี้หลีกเลี่ยงความแหลมคมของซ���ตรัสและความหนักของแป้งเพื่อให้ได้ Korean luxury aesthetic ที่ต้องการ', '2026-05-28', '2026-05-28T09:10:30.318861+00:00', 15, NULL, NULL, NULL, FALSE, NULL, 14, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO formula_versions (id, formula_id, ver, status, rating, notes, blend_date, created_at, batch_ml, projection_actual, longevity_actual, personal_note, is_final, final_date, aging_days, revision_note) VALUES (12, 21, 1, 'Pending', NULL, 'AI แนะนำสูตรเริ่มต้น batch 15ml — สูตรนี้ให้ความรู้สึกสดใสและโปร่งสบายแบบดอกไม้ที่ลอยอยู่ในอากาศ เหมาะสำหรับผู้หญิงสมัยใหม่ที่ต้องการความหอมที่นุ่มนวลและไม่หนักหน่วง', '2026-05-28', '2026-05-28T09:21:29.543478+00:00', 15, NULL, NULL, NULL, FALSE, NULL, 14, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO formula_versions (id, formula_id, ver, status, rating, notes, blend_date, created_at, batch_ml, projection_actual, longevity_actual, personal_note, is_final, final_date, aging_days, revision_note) VALUES (14, 23, 1, 'Pending', NULL, 'AI แนะนำสูตรเริ่มต้น batch 30ml — น้ำหอม Thé Caresse ผสมผสานกลิ่นชาขาวบริสุทธิ์กับมัสค์นุ่มนวล สร้างความรู้สึกสะอาดและเงียบสงบ. ฐานอำพันและไอโซอีซุปเปอร์ให้ความลึกที่นุ่มนวลและยาวนาน เหมาะสำหรับการใส่ในชีวิตประจำวันด้วยความหรูหราที่เรียบง่าย', '2026-05-29', '2026-05-29T20:35:59.939182+00:00', 15, NULL, NULL, NULL, FALSE, NULL, 14, NULL) ON CONFLICT (id) DO NOTHING;
