INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (1, 'Dark Gourmand Evolution', 'กลิ่น Gourmand ในปี 2026 ไม่ได้หอมหวานแบบของหวานอีกต่อไป แต่เปลี่ยนเป็นความลึก ซับซ้อน และเซ็กซี่มากขึ้น เช่น ดาร์กช็อกโกแลต กาแฟ รัม และถั่วผสมกับไม้หรือหนัง สำหรับ indie perfumer นี่คือโอกาสทองในการสร้างกลิ่นที่รู้สึก ''โตขึ้น'' และมีบุคลิกชัดเจน โดยไม่ต้องพึ่งความหวานแบบแมสมาร์เก็ต', ARRAY['Ethyl Maltol','Labdanum Absolute','Coffee CO2 Extract'], NULL, '2026-06-12T13:02:30.673+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (2, 'Pistachio & Nutty Creamy', 'พิสตาชิโอกลายเป็นโน้ตที่ได้รับความนิยมสูงสุดในปี 2026 โดยเติบโตกว่า 852% year-over-year และดึงดูดผู้บริโภคที่ชื่นชอบกลิ่น gourmand แบบครีมี่นุ่มนวล indie perfumer สามารถใช้โน้ตนี้สร้างความโดดเด่นได้ง่าย เพราะยังไม่มีสูตรสำเร็จในตลาด และเปิดโอกาสสร้างเอกลักษณ์เฉพาะตัวได้มาก', ARRAY['Heliotropin','Tonka Bean Absolute','Benzyl Benzoate'], NULL, '2026-06-12T13:02:30.673+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (3, 'Tea & Quiet Luxury', 'กระแส ''Quiet Luxury'' ในโลกน้ำหอมปี 2026 นำมาซึ่งความนิยมของกลิ่นชาทุกชนิด ไม่ว่าจะเป็น Oolong, Matcha, หรือ White Tea ซึ่งให้ความรู้สึกสะอาด สงบ และมีระดับโดยไม่ต้องตะโกน indie perfumer สามารถเล่นกับมิติของชาผสมกับไม้อ่อนหรือมัสก์เพื่อสร้างกลิ่น ''second skin'' ที่ทันสมัยมาก', ARRAY['White Tea Extract','Hedione','Ambroxan'], NULL, '2026-06-12T13:02:30.673+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (4, 'Salty Mineral Skin Scent', 'กลิ่น Marine ในยุคใหม่ไม่ใช่แค่ ozone สังเคราะห์อีกต่อไป แต่วิวัฒน์เป็นกลิ่นเกลือบนผิวหนัง หินริมทะเล และอากาศโล่ง ซึ��งให้ความรู้สึก ''สัมผัสได้จริง'' และหรูหราในแบบเรียบง่าย สำหรับนักทำน้ำหอม indie กลิ่นกลุ่มนี้น่าสนใจมากเพราะยังมีพื้นที่สร้างสรรค์อีกมาก และตอบโจทย์ตลาดที่ต้องการ gender-neutral fragrance', ARRAY['Calone 1951','Ambergris Tincture','Iso E Super'], NULL, '2026-06-12T13:02:30.673+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (5, 'Slow Perfumery & Raw Botanicals', 'ปี 2026 เกิดกระแส ''Slow Perfumery'' ที่เน้นวัตถุดิบธรรมชาติคุณภาพสูง การสกัดแบบ high-altitude และความโปร่งใสในส่วนผสม ผู้บริโภค 72% ให้ความสำคัญกับ clean-label และอยากรู้ว่าน้ำหอมทำมาจากอะไร indie perfumer จึงได้เปรียบมากในแนวทางนี้ เพราะสามารถบอกเล่าที่มาของวัตถุดิบและกระบวนการผลิตได้อย่างจริงใจ สร้างความเชื่อมั่นและความผูกพันกับลูกค้าได้ลึกกว่าแบรนด์ใหญ่', ARRAY['Orris Butter','Frankincense CO2','Vetiver Haiti Essential Oil'], NULL, '2026-06-12T13:02:30.673+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (6, 'Gourmand Goes Dark & Nutty', 'กระแส Gourmand ในปี 2026 ไม่ใช่แค่ความหวานแบบเค้กหรือคาราเมลอีกต่อไป แต่กำลังวิวัฒน์สู่ความซับซ้อนแบบใหม่ โดยเฉพาะกลิ่นพิสตาชิโอที่เติบโตขึ้นถึง 852% ในช่วงปีที่ผ่านมา ผสานกับ Vanilla แบบ toasted และ boozy accord ที่ให้ความลึกและคาแรกเตอร์แข็งแกร่ง นักทำน้ำหอม indie สามารถสร้างความโดดเด่นได้ง่ายในตลาดนี้ เพราะผู้บริโภคกำลังมองหาสูตรที่แปลกและกล้าหาญ ไม่ใช่แค่ความหวานแบบทั่วไป', ARRAY['Pistachio Accord','Ethyl Vanillin','Benzyl Benzoate'], NULL, '2026-06-12T14:15:17.837+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (7, 'Slow Perfumery & Barrel-Aged Oils', 'ปี 2026 เกิดกระแส ''slow perfumery'' อย่างชัดเจน โดยนักทำน้ำหอมหันมาให้ความสำคัญกับกระบวนการที่ใช้เวลาและความพิถีพิถัน เช่น การบ่มน้ำมันหอมในถังโอ๊ค (barrel-aged) หรือการสกัดวัตถุดิบจากระดับความสูงพิเศษ แนวคิดนี้เปิดโอกาสให้ indie perfumer เล่าเรื่องราวเบื้องหลังกรรมวิธีการผลิตได้อย่างน่าสนใจ และสร้างมูลค่าให้กับน้ำหอมผ่านความแท้จริงและงานฝีมือ', ARRAY['Oud','Labdanum Absolute','Leather Accord'], NULL, '2026-06-12T14:15:17.837+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (8, 'Mineral & Molecular Transparency', 'กระแสความสะอาดแบบใหม่ในปี 2026 ก้าวข้ามกลิ่น aquatic ทั่วไป มาสู่ mineral accord ที่ให้ความรู้สึกเหมือนหินเปียก โลหะ และโอโซน ซึ่งสร้างความรู้สึก elemental และทันสมัยอย่างยิ่ง สำหรับ indie perfumer กลุ่มโมเลกุลเหล่านี้ช่วยสร้างกลิ่นที่โปร่ง มีเอกลักษณ์ และแตกต่างจากน้ำหอมกระแสหลักได้อย่างชัดเจน', ARRAY['Iso E Super','Ambrox Super','Hedione'], NULL, '2026-06-12T14:15:17.837+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (9, 'Tea & Matcha Quiet Luxury', 'กลิ่นชา ทั้ง Oolong, Matcha และ Green Tea กำลังเป็นหนึ่งในเทรนด์ที่ได้รับความสนใจมากที่สุดในช่วงครึ่งหลังของปี 2026 โดยตอบโจทย์กระแส ''quiet luxury'' ที่ผู้บริโภคมองหาความสง่างามแบบเรียบง่ายและไม่ตะโกน สำหรับ indie perfumer ชา matcha และชา green tea เป็นวัตถุดิบที่เข้าถึงง่าย แต่สามารถสร้าง accord ที่มีความลึกและเล่าเรื่องได้ โดยเฉพาะเมื่อจับคู่กับ musk หรือ wood', ARRAY['Matcha Extract','White Tea Accord','Ambrette Seed'], NULL, '2026-06-12T14:15:17.837+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (10, 'Transparent Woods & Skin Musks', 'เทรนด์ ''invisible layer'' หรือกลิ่นที่กลมกลืนกับผิวหนังแบบ second skin กำลังเติบโตอย่างมากในปี 2026 โดย transparent wood และ skin musk สร้างกลิ่นที่ดูมีราคา ไม่หนักแน่น และกระตุ้นความรู้สึกใกล้ชิด indie perfumer ที่ทำงานกับ molecular material เช่น Ambroxan หรือ Cashmeran สามารถสร้างน้ำหอมที่รู้สึก ''มีชีวิต'' และตอบสนองต่อเคมีของผิวแต่ละคนได้อย่างน่าประทับใจ', ARRAY['Ambroxan','Cashmeran','White Musk'], NULL, '2026-06-12T14:15:17.837+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (11, 'Gourmand Twist: Pistachio & Salt', 'กระแส Gourmand ในปี 2026 ไม่ใช่แค่ความหวานธรรมดาอีกต่อไป แต่กำลังพัฒนาไปสู่กลิ่นที่ซับซ้อนขึ้น เช่น พิสตาชิโอ คาราเมลเค็ม และวานิลลาที่มีความลึกแบบ Boozy หรือ Smoky Woody Pistachio เพียงอย่างเดียวมียอดค้นหาและโซเชียลพุ่งขึ้นถึง 852% ต่อปี ทำให้เป็นโอกาสทองสำหรับ Indie Perfumer ที่ต้องการสร้างกลิ่น Gourmand ที่แตกต่างและจดจำได้', ARRAY['Heliotropin','Ethyl Maltol','Hazelnut Absolute'], NULL, '2026-06-12T14:19:07.629+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (12, 'Slow Perfumery: Barrel-Aged Oud', 'กระแส Slow Perfumery กำลังมาแรงในหมู่นักทำน้ำหอมอิสระ โดยเน้นกระบวนการที่ช้าและพิถีพิถัน เช่น การหมักน้ำมันใน oak barrel หรือการสกัดจากแหล่งที่ระดับสูง เพื่อให้ได้กลิ่นที่มีมิติและคุณภาพพิเศษ นักทำน้ำหอม Indie สามารถใช้แนวทางนี้สร้างมูลค่าและเรื่องราวที่น่าสนใจรอบผลิตภัณฑ์ของตนได้อย่างมีประสิทธิภาพ', ARRAY['Oud Oil','Leather Accord','Saffron Absolute'], NULL, '2026-06-12T14:19:07.629+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (13, 'Molecular Musk Minimalism', 'ปี 2026 เห็นการเติบโตของ Molecular Musk และ Translucent Woods ที่ให้ความรู้สึก ''Skin Scent'' อันประณีตและทันสมัย กลิ่นกลุ่มนี้ออกแบบมาให้ผสานกับเคมีของผิวหนังผู้สวมใส่ สร้างกลิ่นที่เป็นเอกลักษณ์เฉพาะตัว สำหรับ Indie Perfumer นี่คือโอกาสสร้าง Signature Scent ที่ดูหรูหราแต่ใส่สบาย ตอบโจทย์เทรนด์ Quiet Luxury ได้อย่างตรงจุด', ARRAY['Ambroxan','Iso E Super','Exaltolide'], NULL, '2026-06-12T14:19:07.629+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (14, 'Tea & Matcha Quiet Luxury', 'กลิ่น Tea โดยเฉพาะ Oolong และ Matcha กำลังจะเป็นคลื่นลูกใหม่ของวงการน้ำหอมในช่วงปลายปี 2026 สะท้อนเทรนด์ Quiet Luxury ที่ผู้บริโภครุ่นใหม่มองหาความซับซ้อนที่ไม่ตะโกน แต่มีความลึกทางอารมณ์ Indie Perfumer ที่หยิบจับวัตถุดิบกลุ่มนี้มาทำงานก่อนได้เปรียบอย่างมาก เพราะตลาดยังไม่อิ่มตัวและผู้บริโภคพร้อมสำรวจ', ARRAY['White Tea Accord','Matcha Green Tea Absolute','Hedione'], NULL, '2026-06-12T14:19:07.629+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (15, 'Mineral & Ozonic Neo-Florals', 'กระแส Elemental Minimalism นำพา Mineral Accord, Ozonic Note และ Neo-Florals เข้ามาเป็นภาษาใหม่ของน้ำหอมปี 2026 โดยจับเอาความบริสุทธิ์ของอากาศ หิน และน้ำมาถ่ายทอดเป็นกลิ่น นักทำน้ำหอม Indie สามารถสร้างผลงานที่รู้สึก ''Futuristic'' และ ''Avant-Garde'' ด้วยวัตถุดิบกลุ่มนี้ ซึ่งยังไม่ถูกใช้อย่างแพร่หลายในตลาด Mass จึงเป็นพื้นที่สร้างสรรค์ที่ยังเปิดกว้างมาก', ARRAY['Calone','Akigalawood','Rose Oxide'], NULL, '2026-06-12T14:19:07.629+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (16, 'Gourmand With a Dark Twist', 'เทรนด์ gourmand ในปี 2026 ไม่ได้หยุดอยู่แค่วานิลลาและคาราเมลธรรมดาอีกต่อไป แต่กำลังวิวัฒน์ไปสู่ความซับซ้อนที่มีมิติลึกขึ้น เช่น pistachio ที่มีความครีมี, โทนบูร์บงอบอุ่น, และวานิลลาที่ผสานกับ oud จนให้ความรู้สึกดิบและเซ็กซี่ยิ่งขึ้น สำหรับ indie perfumer แนวนี้เปิดโอกาสสร้างสรรค์ความหอมที่ให้ทั้งความคุ้นเคยและความแปลกใหม่ในขวดเดียวกัน', ARRAY['Pistachio Accord','Ethyl Vanillin','Oud'], NULL, '2026-06-12T14:41:38.571+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (17, 'Slow Perfumery & Barrel Aging', 'กระแส ''slow perfumery'' กำลังมาแรงในหมู่นักทำน้ำหอม niche โดยเน้นกระบวนการผลิตที่ช้าและพิถีพิถัน เช่น การบ่มน้ำมันในถังโอ๊ค หรือการสกัดด้วยความสูงเพื่อให้ได้กลิ่นที่ลึกและซับซ้อนกว่าเดิม แนวทางนี้ดึงดูด indie perfumer ที่ต้องการสร้างความแตกต่างด้วยคุณภาพของวัตถุดิบและเรื่องราวเบื้องหลังสูตรหอม', ARRAY['Aged Oud','Leather Accord','Labdanum'], NULL, '2026-06-12T14:41:38.571+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (18, 'Molecular Transparency & Clean Woods', 'นักทำน้ำหอม niche และผู้บริโภคปี 2026 ต่างหันมาสนใจกลิ่นที่ ''โปร่ง'' และ ''อบอุ่นบนผิว'' มากกว่ากลิ่นที่หนักและฉุน โดยวัตถุดิบสังเคราะห์อย่าง Ambroxan และ Cashmeran ช่วยสร้างกลิ่นไม้ที่เบาแต่ติดทน เหมาะสำหรับ indie perfumer ที่อยากทำน้ำหอม unisex ในสไตล์ quiet luxury ที่ให้ความรู้สึกเหมือนกลิ่นผิวที่สอง', ARRAY['Ambroxan','Cashmeran','Sylvanone'], NULL, '2026-06-12T14:41:38.571+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (19, 'Matcha & Tea Neo-Florals', 'เทรนด์ชา โดยเฉพาะ matcha และ oolong กำลังก้าวเข้าสู่วงการน้ำหอม niche อย่างจริงจัง สะท้อนวัฒนธรรม quiet luxury และความนิยมของ ''clean scent'' แบบเอเชีย วัตถุดิบอย่าง White Tea Accord ผสาน Hedione และดอกไม้ biotech ให้ความสดชื่นที่ยังมีความลึกแบบ floral-green สำหรับ indie perfumer แนวนี้คือโอกาสทองในการเจาะกลุ่มคนรุ่นใหม่ที่ต้องการกลิ่นที่บอกเล่าเรื่องราวของธรรมชาติและวัฒนธรรม', ARRAY['White Tea Accord','Hedione','Green Violet'], NULL, '2026-06-12T14:41:38.571+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (20, 'Mineral & Metallic Skin Scents', 'แนวกลิ่นที่ได้แรงบันดาลใจจากธรรมชาติทางธรณีวิทยา เช่น หินเปียก โอโซน และโลหะ กำลังเป็นที่พูดถึงอย่างมากในปี 2026 โดย Iso E Super และ sea salt accord ช่วยสร้างความรู้สึกสะอาด ลึก และเป็นนามธรรมในแบบที่กลิ่นดอกไม้ธรรมดาทำไม่ได้ นี่คือทิศทางที่ indie perfumer สามารถสำรวจ ''อารมณ์'' และ ''ความรู้สึก'' แทนที่จะยึดติดกับวัตถุดิบคลาสสิก', ARRAY['Iso E Super','Sea Salt Accord','Metallic Aldehyde'], NULL, '2026-06-12T14:41:38.571+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (21, 'Boozy & Salty Gourmands', 'กลิ่นกูร์มองด์ในปี 2026 ไม่ได้หอมหวานแบบขนมอีกต่อไป แต่วิวัฒน์สู่ความซับซ้อนแบบ ''Boozy Gourmand'' ที่มีกลิ่นเหล้า เกลือ และคาราเมลผสมกันอย่างลงตัว เทรนด์นี้น่าสนใจสำหรับ indie perfumer เพราะเปิดพื้นที่ให้ทดลองวัตถุดิบที่ขัดแย้งกัน เช่น ความหวานตัดกับความเค็มหรือควัน ทำให้ได้กลิ่นที่มีบุคลิกชัดเจนและจดจำได้ง่ายในตลาด', ARRAY['Ethyl Maltol','Iso E Super','Sea Salt Accord'], NULL, '2026-06-12T14:42:25.598+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (22, 'Mineral & Metallic Accords', 'กลิ่นแร่ธาตุและโลหะกำลังก้าวขึ้นมาเป็นเทรนด์ใหม่ในวงการน้ำหอม niche โดยสื่อถึงความรู้สึกของหินเปียก อากาศบริสุทธิ์ และแร่เหล็ก อันเป็นการตอบรับความต้องการของผู้บริโภคที่มองหาความ ''โปร่ง'' และ ''เรียบหรู'' แบบใหม่ นักน้ำหอมอิสระสามารถใช้โอกาสนี้สร้างกลิ่นแนว avant-garde ที่ดูแตกต่างจากน้ำหอมกระแสหลักได้อย่างโดดเด่น', ARRAY['Iso E Super','Ambrox Super','Metallic Aldehyde'], NULL, '2026-06-12T14:42:25.598+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (23, 'Pistachio & Nutty Niche', 'พิสตาชิโอกลายเป็นโน้ตดาวเด่นแห่งปี 2026 ด้วยตั��เลขการค้นหาที่พุ่งสูงถึง 852% เมื่อเทียบปีต่อปี สะท้อนถึงความหลงใหลของผู้บริโภคในกลิ่น ''ครีมี นัตตี้'' ที่ให้ความรู้สึกอบอุ่นและหรูหราโดยไม่จัดจ้าน สำหรับ indie perfumer เทรนด์นี้คือโอกาสทองในการสร้างกลิ่นกูร์มองด์ที่มีเอกลักษณ์ต่างจากวานิลลาและช็อกโกแลตที่คุ้นเคย', ARRAY['Pistachio Accord','Heliotropin','Tonka Bean'], NULL, '2026-06-12T14:42:25.598+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (24, 'Transparent Woods & Skin Scents', 'กลิ่นไม้แบบ ''โปร่งใส'' และ skin scent กำลังได้รับความนิยมอย่างมากในกลุ่มนักสะสมน้ำหอม niche ที่ต้องการกลิ่นที่ดูเหมือนกลมกลืนเป็นส่วนหนึ่งของผิวหนัง ไม่หนักหรือฉุน เทรนด์นี้เน้นการใช้โมเลกุลสังเคราะห์คุณภาพสูงเพื่อสร้างความลึกที่ละเมียดและ dry-down ที่งดงาม ซึ่งเปิดโอกาสให้ indie perfumer แสดงฝีมือทางเทคนิคได้อย่างเต็มที่', ARRAY['Ambroxan','Cashmeran','Sylvanone'], NULL, '2026-06-12T14:42:25.598+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (25, 'Tea & Matcha Botanicals', 'กลิ่นชา โดยเฉพาะ Oolong และ Matcha กำลังกลายเป็นคลื่นลูกใหม่ในน้ำหอม niche ปลายปี 2026 สอดรับกับเทรนด์ ''quiet luxury'' ที่ผู้บริโภคต้องการความสงบเรียบหรูแทนการโชว์แบรนด์ กลิ่นชามีความหลากหลายของแฟมิลี่ตั้งแต่เขียวอ่อน ดินหอม ไปจนถึงครีมมี่ ทำให้นักน้ำหอมอิสระสามารถนำมาผสมผสานกับวัตถุดิบอื่น ๆ ได้อย่างสร้างสรรค์และไม่ซ้ำใคร', ARRAY['Matcha Accord','White Tea Extract','Hedione'], NULL, '2026-06-12T14:42:25.598+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (26, 'Salty & Boozy Gourmand Twist', 'กระแส Gourmand ในปี 2026 ไม่ใช่แค่ขนมหวานธรรมดาอีกต่อไป แต่เริ่มซับซ้อนขึ้นด้วยการผสมความเค็ม ความขมของแอลกอฮอล์ และความครีมีเข้าด้วยกัน เช่น Pistachio + Rum หรือ Caramel + Sea Salt น้ำหอม Pistachio คนเดียวพุ่งขึ้นถึง 852% ในช่วงปีที่ผ่านมา ทำให้นักทำน้ำหอม Indie มีโอกาสทองในการสร้างสรรค์สูตรที่แปลกและน่าจดจำ', ARRAY['Pistachio Lactone','Ethyl Maltol','Rum Ether'], NULL, '2026-06-12T14:45:16.827+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (27, 'Molecular Musk & Skin Scents', 'น้ำหอมกลิ่น ''ผิวหนัง'' ที่ดูเหมือนกลิ่นตัวเองในแบบที่สมบูรณ์แบบกำลังมาแรงมากในหมู่นักสะสมนิช โดยใช้ Musk โมเลกุลและวัตถุดิบสังเคราะห์ที่โปร่งใส เพื่อสร้างกลิ่นที่แนบชิดกับผู้สวมใส่และพัฒนาไปตาม Body Chemistry สำหรับนักทำน้ำหอม Indie นี่คือโอกาสที่จะสร้างน้ำหอม ''เซ็กซ์ซี่เงียบๆ'' ที่ดูเหมือนไม่ได้ใส่น้ำหอมแต่หอมอย่างลึกลับ', ARRAY['Ambroxan','Iso E Super','White Musk'], NULL, '2026-06-12T14:45:16.827+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (28, 'Tea & Matcha Quiet Luxury', 'กระแส Quiet Luxury ดันให้กลิ่นชา โดยเฉพาะ Oolong, Matcha และ White Tea กลายเป็นหัวใจของน้ำหอมนิชปี 2026 แบรนด์อย่าง Nishane และ Byredo ต่างพากันเตรียมปล่อยสูตรชาใหม่ในช่วงปลายปี กลิ่นชาให้ความสะอาด ลึก และทันสมัยโดยไม่จำเป็นต้องพึ่งวัตถุดิบราคาแพง เหมาะมากสำหรับนักทำน้ำหอมอิสระที่ต้องการสร้างงานสละสลวยในราคาที่เข้าถึงได้', ARRAY['White Tea Absolute','Hedione','Linalool'], NULL, '2026-06-12T14:45:16.827+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (29, 'Elemental Mineral & Ozonic Accord', 'ปี 2026 เปิดตัวทิศทางใหม่ที่เรียกว่า Elemental Minimalism ซึ่งเน้นกลิ่นหิน น้ำ และโอโซนที่ให้ความรู้สึกบริสุทธิ์และเป็นธรรมชาติอย่างลึกซึ้ง นักทำน้ำหอม Indie สามารถใช้โอกาสนี้สร้างน้ำหอมที่แตกต่างอย่างสิ้นเชิงจากกระแสหวานและหรูหรา โดยเล่นกับวัตถุดิบ Aldehyde, Calone และ Cashmeran เพื่อจำลองกลิ่นธาตุธรรมชาติในแบบศิลปะ', ARRAY['Calone','Cashmeran','Aldehyde C-12 MNA'], NULL, '2026-06-12T14:45:16.827+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (30, 'Fruity Oud East-West Fusion', 'การผสมผสานระหว่างกลิ่น Oud จากตะวันออกกลางและ Fruity Notes จากตะวันตก เช่น Raspberry, Lychee หรือ Peach ยังคงเป็นหนึ่งในทิศทางที่แข็งแกร่งที่สุดในปี 2026 ความผสมนี้ช่วยให้ Oud ซึ่งมักรู้สึกหนักและ Animalic มีความอ่อนโยนและเข้าถึงได้มากขึ้น นักทำน้ำหอม Indie ที่ต้องการดึงดูดทั้งตลาดเอเชียและตะวันตกควรทดลองกับ Accord นี้เพราะมีความลึกและเล่าเรื่องได้อย่างทรงพลัง', ARRAY['Oud Essential Oil','Raspberry Ketone','Saffron Absolute'], NULL, '2026-06-12T14:45:16.827+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (31, 'Dark Gourmand & Savory Depth', 'เทรนด์นี้ก้าวพ้นความหวานแบบเดิมไปสู่กลิ่น Gourmand ที่มีความซับซ้อนและมีเนื้อสัมผัส เช่น โกโก้ขม, รัม, กาแฟ และถั่วพิสตาชิโอ ผสานกับเบสที่อบอุ่นอย่างหนัง ไม้ และควัน นักทำน้ำหอมอินดี้สามารถสร้างสรรค์กลิ่นที่ดูผู้ใหญ่และมีบุคลิกโดดเด่น ห่างไกลจากความหวานฉาบฉวยของตลาดแมส', ARRAY['Ethyl Maltol','Iso E Super','Labdanum','Tonka Bean Absolute','Coffee CO2 Extract'], NULL, '2026-06-12T14:47:40.254+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (32, 'Mineral & Metallic Accords', 'กลิ่นแร่ธาตุและโลหะกำลังได้รับความนิยมสูงในหมู่นักสะสมน้ำหอมนิช โดยสื่อถึงความรู้สึกของหินเปียก โอโซน และอากาศบริสุทธิ์ที่มีความลึกแบบนามธรรม เทรนด์นี้เปิดโอกาสให้นักทำน้ำหอมอิสระได้ทดลองกับโมเลกุลสังเคราะห์ที่ทันสมัยและแหวกแนว', ARRAY['Iso E Super','Ambrox Super','Sea Salt Accord','Ambroxan','Hedione'], NULL, '2026-06-12T14:47:40.254+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (33, 'Tea & Matcha Botanicals', 'กลิ่นชาสไตล์ต่าง ๆ ไม่ว่าจะเป็นอูหลง มัทฉะ หรือชาเขียว กำลังเป็นกระแสแรงในช่วงครึ่งหลังของปี 2026 สอดรับกับเทรนด์ความเงียบหรูหรา (Quiet Luxury) ที่ผู้บริโภคต้องการความสงบและประณีต นักทำน้ำหอมอินดี้สามารถใช้วัตถุดิบนี้สร้างกลิ่นที่ดูสะอาดและมีเอกลักษณ์เฉพาะตัว', ARRAY['White Tea Extract','Green Tea Absolute','Hedione','Violet Leaf Absolute','Cedarwood Atlas'], NULL, '2026-06-12T14:47:40.254+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (34, 'Skin-Scent & Neo Musks', 'กลิ่น Skin Scent หรือน้ำหอมที่ดูเหมือนกลิ่นผิวหนังตัวเองยังคงแข็งแกร่งในปี 2026 โดยเน้นมัสก์โมเลกุลที่โปร่งใสและเบา เช่น Ambrette และ White Musk ผสานกับไม้อ่อนนุ่ม สำหรับนักทำน้ำหอมนิช เทรนด์นี้น่าสนใจเพราะช่วยให้สร้างกลิ่นที่ใส่แล้วกลมกลืนกับผู้สวมใส่แต่ละคนได้อย่างไม่เหมือนใคร', ARRAY['Ambrette Seed Absolute','White Musk','Cashmeran','Sandalwood Mysore','Galaxolide'], NULL, '2026-06-12T14:47:40.254+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (35, 'Slow Perfumery & Rare Resins', 'กระแส Slow Perfumery คือการหันกลับสู่วัตถุดิบธรรมชาติชั้นดีและหายาก เช่น น้ำมันอูดหมัก, ยางไม้โบราณ และสารสกัดที่ผ่านกระบวนการพิถีพิถัน นักทำน้ำหอมอิสระได้เปรียบในเทรนด์นี้เพราะสามารถทำงานในสเกลเล็กที่เน้นคุณภาพและเล่าเรื่องราวของวัตถุดิบแต่ละชิ้นได้อย่างลึกซึ้ง', ARRAY['Oud Oil','Frankincense Resin Absolute','Benzyl Benzoate','Labdanum Absolute','Myrrh Resinoid'], NULL, '2026-06-12T14:47:40.254+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (36, 'Dark Gourmand Depth', 'เทรนด์นี้ก้าวข้ามความหวานแบบขนมหวาน โดยหันมาสู่กลิ่นกูร์มองด์ที่มีความลึก ซับซ้อน และมีเนื้อสัมผัส เช่น โกโก้ขม รัม กาแฟ และวานิลลาคู่กับไม้หรือควัน นักทำน้ำหอมอินดี้จะได้เปรียบมากในเทรนด์นี้ เพราะสามารถสร้างสูตรที่กล้าและมีเอกลักษณ์ได้โดยไม่ต้องกังวลเรื่องตลาดแมส', ARRAY['Ethyl Vanillin','Dark Rum Absolute','Cacao Absolute'], NULL, '2026-06-12T14:48:50.138+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (37, 'Slow Perfumery Movement', 'กระแส Slow Perfumery เน้นกระบวนการสร้างน้ำหอมด้วยความตั้งใจและความประณีต เช่น การสกัดที่ระดับความสูง น้ำมันที่บ่มด้วยถังไม้โอ๊ก และสูตรที่ออกแบบมาเพื่อส่งผลต่ออารมณ์ สำหรับนักทำน้ำหอมอินดี้ เทรนด์นี้เปิดโอกาสให้สร้างน้ำหอมที่มีความลึกและเรื่องราวที่แท้จริง แทนที่จะแข่งขันด้านปริมาณ', ARRAY['Oud Resinoid','Benzyl Benzoate','Frankincense Absolute'], NULL, '2026-06-12T14:48:50.138+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (38, 'Tea & Matcha Botanicals', 'กลิ่นชาในรูปแบบต่าง ๆ โดยเฉพาะมัทฉะและอูหลง กำลังเติบโตอย่างก้าวกระโดด โดยข้อมูลพบว่าความสนใจในกลิ่นมัทฉะเพิ่มขึ้นกว่า 173% ต่อปี เทรนด์นี้เหมาะอย่างยิ่งกับนักทำน้ำหอมอินดี้ที่ต้องการสร้างกลิ่นสดชื่น เป็นธรรมชาติ และดึงดูดกลุ่ม Quiet Luxury', ARRAY['Matcha Extract','White Tea Absolute','Hedione'], NULL, '2026-06-12T14:48:50.138+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (39, 'Skin Scent & Musk Intimacy', 'น้ำหอมที่ให้กลิ่นเหมือน ''ผิวหนังที่สะอาดและมีเสน่ห์'' กำลังได้รับความนิยมสูง เน้นความรู้สึกใกล้ชิด นุ่มนวล และเป็นส่วนตัว ไม่ใช่กลิ่นที่โฉบเฉี่ยว นักทำน้ำหอมอินดี้สามารถใช้โอกาสนี้สร้างน้ำหอมที่มีความเป็น ''Signature'' สูง เพราะกลิ่นประเภทนี้จะเปลี่ยนแปลงไปตามเคมีของผิวแต่ละคน', ARRAY['Ambrette Seed','Iso E Super','White Musk'], NULL, '2026-06-12T14:48:50.138+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (40, 'Functional Mood Fragrance', 'ผู้บริโภคปี 2026 เลือกน้ำหอมเพื่อ ''รู้สึก'' บางอย่าง เช่น ช่วยให้สมาธิ ผ่อนคลาย หรือกระตุ้นพลังงาน ไม่ใช่แค่ ''หอม'' เทรนด์นี้เชื่อมโยงกับศาสตร์ด้าน Scent Neuroscience และเปิดพื้นที่ใหม่ให้นักทำน้ำหอมอินดี้สร้างผลิตภัณฑ์ที่มีจุดประสงค์ชัดเจนและเล่าเรื่องได้ลึกซึ้งกว่าน้ำหอมทั่วไป', ARRAY['Lavender Absolute','Ambroxan','Bergamot Essential Oil'], NULL, '2026-06-12T14:48:50.138+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (41, 'Dark Gourmand Evolved', 'ในปี 2026 กลิ่น Gourmand ไม่ได้หวานแบบขนมหวานอีกต่อไป แต่วิวัฒน์ไปสู่ความลึกและความซับซ้อนมากขึ้น เช่น ช็อกโกแลตขมคู่กับไม้รมควัน หรือวานิลลาจับคู่กับหนังและอำพัน เทรนด์นี้น่าสนใจสำหรับ indie perfumer เพราะเปิดพื้นที่สร้างสรรค์กลิ่นที่ดูผู้ใหญ่ เซ็กซี่ และมีเอกลักษณ์โดยไม่ต้องพึ่งความหวานแบบ mass market', ARRAY['Ethyl Maltol','Cashmeran','Labdanum Absolute'], NULL, '2026-06-12T15:03:43.255+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (42, 'Mineral & Metallic Accords', 'กลิ่นแนว mineral และ metallic กำลังมาแรงในปี 2026 โดยสื่อถึงภาพหินเปียก โลหะ และอากาศบริสุทธิ์ที่เป็นนามธรรมแต่ให้ความรู้สึก grounded น่าสนใจสำหรับ indie perfumer ที่ต้องการทำลายกรอบของกลิ่นดอกไม้และไม้แบบเดิม โดยสามารถสร้าง concept ที่แปลกใหม่และทรงพลังด้วยวัตถุดิบ synthetic ที่ทันสมัย', ARRAY['Iso E Super','Ambrox Super','Metallic Aldehydes'], NULL, '2026-06-12T15:03:43.255+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (43, 'Transparent Skin Musks', 'เทรนด์กลิ่น skin-close musk ที่รู้สึกเหมือนเป็นส่วนหนึ่งของผิวหนังกำลังได้รับความนิยมอย่างมาก ผู้สวมใส่ต้องการกลิ่นที่ intimate และ personal ไม่ใช่กลิ่นที่ประกาศตัวเองดังๆ สำหรับ indie perfumer นี่คือโอกาสทองในการสร้างกลิ่น ''second skin'' ที่ลูกค้าอยากสวมใส่ทุกวัน โดยใช้ musk โปร่งใสและ lactonic notes เป็นแกนหลัก', ARRAY['Habanolide','Ethylene Brassylate','Ambrette Seed'], NULL, '2026-06-12T15:03:43.255+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (44, 'Pistachio & Nutty Gourmands', 'Pistachio กลายเป็นหนึ่งในส่วนผสมที่เติบโตเร็วที่สุดในวงการน้ำหอมปี 2026 โดยมีการเติบโตของ search volume สูงมากบน TikTok และ Google กลิ่นถั่วพิสตาชิโอให้ความรู้สึก creamy และ nutty แต่ไม่หวานเกินไป indie perfumer สามารถนำ concept นี้มาผสมกับ tobacco, leather หรือ smoke เพื่อสร้างกลิ่น gourmand ที่มีมิติและไม่ซ้ำใคร', ARRAY['Heliotropin','Tonka Bean Absolute','Coumarin'], NULL, '2026-06-12T15:03:43.255+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (45, 'Tea & Matcha Botanicals', 'กลิ่นชาในรูปแบบต่างๆ ทั้ง oolong, matcha และ white tea กำลังเป็นกระแสใหญ่ที่ตอบโจทย์เทรนด์ ''quiet luxury'' และ ''clean scent'' ในปี 2026 เป็นกลิ่นที่ให้���วามรู้สึก sophisticated โดยไม่ต้องหนักหน่วง indie perfumer ในไทยมีข้อได้เปรียบพิเศษในการเข้าถึง botanical จากชา และสามารถผสมผสานกับ green note หรือ woody accord เพื่อสร้าง signature ที่มีรากฐานจากเอเชีย', ARRAY['White Tea Extract','Hedione','Violet Leaf Absolute'], NULL, '2026-06-12T15:03:43.255+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (46, 'Gourmand Evolved: Pistachio & Salt', 'กระแส Gourmand ในปี 2026 ไม่ใช่แค่วานิลลาหรือคาราเมลอีกต่อไป แต่หันมาสู่กลิ่นถั่วพิสตาชิโอที่มีความครีมี ซับซ้อน และมีมิติของความเค็มแทรก ทำให้กลิ่นรู้สึกน่าสนใจและแปลกใหม่กว่าเดิม นักทำน้ำหอม indie มีโอกาสสูงมากเพราะ pistachio เติบโตสูงถึง 852% ต่อปีในโซเชียลมีเดีย และผู้บริโภคยังมองหาแบรนด์เล็กที่นำเสนอสูตรเฉพาะตัวได้ก่อนแบรนด์ใหญ่', ARRAY['Pistachio Lactone','Ethyl Maltol','Ambroxan'], NULL, '2026-06-12T15:05:27.442+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (47, 'Slow Perfumery: Barrel-Aged Depth', 'แนวคิด ''Slow Perfumery'' กำลังมาแรงในปี 2026 โดยเน้นการใช้น้ำมันหอมที่ผ่านกระบวนการบ่มหรือสกัดแบบ High-altitude เพื่อให้กลิ่นมีความลึกและซับซ้อนผิดปกติ กลิ่นที่ได้จะมีความ Oud, Leather, หรือ Resin ที่ฝังลึกและคงทนนานบนผิว แนวทางนี้เหมาะสำหรับ indie perfumer ที่ต้องการนำเสนอความแท้จริงและคราฟต์แมนชิพ ซึ่งเป็นสิ่งที่ผู้บริโภคสมัยใหม่ให้ความสำคัญมากขึ้น', ARRAY['Oud','Labdanum Absolute','Iso E Super'], NULL, '2026-06-12T15:05:27.442+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (48, 'Molecular Musk & Transparent Woods', 'ปี 2026 เห็นการเติบโตของกลิ่น Musk แบบโมเลกุลและ Transparent Woods ที่ให้ความรู้สึกโปร่ง สะอาด และแนบเนื้อผิว ไม่ใช่กลิ่นฉุนหรือหนักแบบดั้งเดิม แนวทางนี้สะท้อน ''Elemental Minimalism'' ซึ่งจับภาพความบริสุทธิ์ของธรรมชาติไว้ในรูปแบบสมัยใหม่ สำหรับ indie perfumer แนวนี้ช่วยสร้าง signature scent ที่แตกต่างจากตลาดใหญ่ได้ชัดเจน เพราะต้องการความเชี่ยวชาญด้านวัสดุโมเลกุลเป็นพิเศษ', ARRAY['Habanolide','Cashmeran','Javanol'], NULL, '2026-06-12T15:05:27.442+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (49, 'Tea & Matcha Quiet Luxury', 'กลิ่นชา โดยเฉพาะ Oolong และ Matcha กำลังจะระเบิดตลาดในช่วงปลายปี 2026 ขับเคลื่อนโดยกระแส ''Quiet Luxury'' ที่ผู้บริโภคต้องการกลิ่นที่สง่างาม ไม่โอ้อวด แต่แสดงถึงรสนิยม น้ำหอม indie สามารถเจาะตลาดนี้ได้ก่อนแบรนด์ใหญ่ที่ยังอยู่ในระหว่างพัฒนาผลิตภัณฑ์ โดยการผสมกลิ่น Green Tea หรือ Matcha เข้ากับ Musk หรือ Wood เพื่อสร้างความสมดุลที่ดูหรูหราแต่เข้าถึงได้', ARRAY['Green Tea Absolute','Hedione','White Musk'], NULL, '2026-06-12T15:05:27.442+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (50, 'Skin-Scent Storytelling', 'กระแส ''Skin-ification of Scent'' ที่ผสานน้ำหอมเข้ากับความรู้สึกของผิวหนังกำลังเติบโตอย่างต่อเนื่อง โดยกลิ่นที่ได้รับความนิยมจะวิวัฒน์ไปตามเคมีผิวของผู้สวมใส่แต่ละคน สไตล์นี้เหมาะอย่างยิ่งกับ indie perfumer เพราะมันต้องการการเล่าเรื่องที่ลึกและเฉพาะตัว ซึ่งแบรนด์ขนาดเล็กทำได้ดีกว่าบริษัทใหญ่ที่ต้องผลิตในปริมาณมาก วัสดุอย่าง Ambrette หรือ Skin-like Musk จะเป็นหัวใจสำคัญของแนวทางนี้', ARRAY['Ambrette Seed Absolute','Ethylene Brassylate','Benzyl Benzoate'], NULL, '2026-06-12T15:05:27.442+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (51, 'Slow Perfumery & Barrel-Aged Oils', 'เทรนด์ ''Slow Perfumery'' คือการสร้างน้ำหอมที่ใช้เวลาและความตั้งใจ เช่น การหมักน้ำมันในถังโอ๊คหรือการสกัดจากแหล่งที่สูง เพื่อให้ได้กลิ่นที่ลึกและซับซ้อนกว่าน้ำหอมทั่วไป สำหรับ Indie Perfumer เทรนด์นี้เปิดโอกาสในการสร้างเอกลักษณ์เฉพาะตัวด้วยวัตถุดิบคุณภาพสูงและกระบวนการผลิตที่มีเรื่องราว', ARRAY['Oud Resin','Labdanum Absolute','Sandalwood CO2'], NULL, '2026-06-12T15:06:19.9+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (52, 'Sophisticated Gourmand Twist', 'น้ำหอมกูร์มองด์ยุคใหม่ไม่ได้หอมหวานเหมือนขนมเค้กอีกต่อไป แต่ผสมผสานความหวานเข้ากับความเปรี้ยว รมควัน หรือกลิ่นสัตว์เพื่อสร้างความลึกและความน่าประหลาดใจ Indie Perfumer สามารถสร้างความโดดเด่นได้โดยการจับคู่วัตถุดิบที่ไม่คาดคิด เช่น พิสตาชิโอกับไม้รมควัน หรือคาราเมลกับน้ำผึ้งและกลิ่นหนัง', ARRAY['Pistachio Lactone','Ethyl Maltol','Castoreum Absolute'], NULL, '2026-06-12T15:06:19.9+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (53, 'Tea & Quiet Luxury Scents', 'กลิ่นชาประเภทต่าง ๆ เช่น Oolong และ Matcha กำลังเป็นที่นิยมสูงมาก สะท้อนเทรนด์ ''Quiet Luxury'' ที่ผู้บริโภคมองหากลิ่นที่สงบ สะอาด และมีความหรูหราอย่างละเมียดละไม สำหรับ Indie Perfumer นี่คือโอกาสสร้างน้ำหอมที่ให้ความรู้สึกเป็น ''Second Skin'' และบ่งบอกรสนิยมอย่างเงียบ ๆ', ARRAY['White Tea Extract','Hedione','Ambrette Seed'], NULL, '2026-06-12T15:06:19.9+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
