INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (55, 'Biotech & Upcycled Ingredients', 'ความก้าวหน้าด้าน Biotech ทำให้เกิดวัตถุดิบน้ำหอมสังเคราะห์รูปแบบใหม่ที่เลียนแบบกลิ่นธรรมชาติหายากโดยไม่ทำลายสิ่งแวดล้อม รวมถึงการนำของเหลือจากอุตสาหกรรมอื่นมาสกัดเป็นส่วนผสมน้ำหอม เทรนด์นี้น่าสนใจสำหรับ Indie Perfumer ที่ต้องการสร้างน้ำหอมที่มีจุดยืนด้านความยั่งยืนและเล่าเรื่องได้อย่างมีความหมาย', ARRAY['Ambroxan','Haiku Molecule (Okoumal)','Clearwood'], NULL, '2026-06-12T15:06:19.9+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (56, 'Sustainable Botanical Luxury', 'แนวโน้มนี้เน้นการใช้วัตถุดิบจากพืชที่เก็บเกี่ยวอย่างยั่งยืนและวิธีการสกัดที่เป็นมิตรต่อสิ่งแวดล้อม น้ำหอมอินดี้ที่ใช้วัตถุดิบธรรมชาติแบบเซอร์টิฟายจะดึงดูดผู้บริโภคที่ตระหนักรู้เรื่องสิ่งแวดล้อม ผู้ผลิตอิสระสามารถสร้างเอกลักษณ์ผ่านการจัดหาวัตถุดิบที่โปร่งใส', ARRAY['Hedione','Petrichor','Iso E Super'], NULL, '2026-06-12T15:11:05.788+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (57, 'Powdery Comfort Minimalism', 'ความนิยมในการกลับไปสู่สูตรที่เรียบง่ายแต่มีความลึกซึ่งมีกลิ่นนุ่มนวลและสงบ บริษัทอินดี้สามารถสร้างน้ำหอมไขมันสูงโดยใช้วัตถุดิบแบบพาวเดอรี่ที่สร้างความรู้สึกหนักแน่น ทรend นี้ตรงกับความปรารถนาของผู้ที่ชื่นชอบการหลีกหนีความวุ่นวาย', ARRAY['Skin Musk','Galaxolide','Ethyl Vanillin'], NULL, '2026-06-12T15:11:05.788+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (58, 'Animalic Renaissance', 'วัตถุดิบสัตว์เลี้ยงจำพวกแอมเบอร์และมัสก์กลับมาเป็นที่นิยมในบรรดาผู้บริโภคที่ต้องการกลิ่นที่กล้าหาญและเป็นส่วนตัว อินดี้เพอร์ฟิউมเมอร์สามารถสร้างลายเซ็นต์ที่มีความสง่างามและเป็นปัจจุบัน ด้วยการสมดุลของแอมเบอร์และส่วนประกอบกลั่นแกน้อยลง', ARRAY['Ambroxan','Iso E Super','Patchouli'], NULL, '2026-06-12T15:11:05.788+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO trend_items (id, title, description, keywords, source, fetched_at, is_saved, saved_note, is_done, formula_id) VALUES (59, 'Aquatic Transparency', 'กลิ่นน้ำแกร่งที่มีความชัดเจนและความสะอาดซึ่งสร้างแรงบันดาลใจจากเสน่ห์ธรรมชาติของน้ำจืด ผู้ผลิตอินดี้สามารถใช้วัตถุดิบสมัยใหม่เพื่อสร้างกลิ่นที่รู้สึกว่าจริงและเรียบง่าย แต่มีความยั่งยืนตลอดวัน', ARRAY['Calone','Hedione','Neral'], NULL, '2026-06-12T15:11:05.788+00:00', FALSE, NULL, FALSE, NULL) ON CONFLICT (id) DO NOTHING;
